+type Clause = { patterns?: unknown[]; predicate?: (value: unknown) => unknown; handler: (selection: unknown, value: unknown) => unknown };
+type Step = { kind: 'clause'; clause: Clause } | { kind: 'tap'; callback: (result: unknown) => void };
+
+/**
+ * Like `match`, but evaluates every matching clause and returns all results.
+ * Calling without a value builds a reusable matcher through `.toFunction()`.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): any {
+  return new MatchEachExpression(value, arguments.length > 0, []);
+}
