+class MatchEachExpression {
+  constructor(private value: unknown, private hasValue: boolean, private steps: Step[]) {}
+
+  with(...args: any[]) {
+    const handler = args[args.length - 1];
+    const patterns = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+    return this.add({ kind: 'clause', clause: { patterns, predicate, handler } });
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown) {
+    return this.add({ kind: 'clause', clause: { predicate, handler } });
+  }
+
+  tap(callback: (result: unknown) => void) { return this.add({ kind: 'tap', callback }); }
+  otherwise(handler: (value: unknown) => unknown) {
+    const results = this.evaluate(this.requireValue());
+    return results.length ? results : [handler(this.value)];
+  }
+  exhaustive(fallback?: (value: unknown) => unknown) {
+    const results = this.evaluate(this.requireValue());
+    if (results.length) return results;
+    if (fallback) return [fallback(this.value)];
+    throw new NonExhaustiveError(this.value);
+  }
+  run() { return this.exhaustive(); }
